import{_ as t,o as a,c as i,ag as o}from"./chunks/framework.NIzFHKo_.js";const u=JSON.parse('{"title":"Schema","description":"","frontmatter":{},"headers":[],"relativePath":"10_core/30_data/90_schema.md","filePath":"10_core/30_data/90_schema.md"}'),r={name:"10_core/30_data/90_schema.md"};function d(n,e,c,s,l,h){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="schema" tabindex="-1">Schema <a class="header-anchor" href="#schema" aria-label="Permalink to &quot;Schema&quot;">​</a></h1><h2 id="current-doctrine" tabindex="-1">Current Doctrine <a class="header-anchor" href="#current-doctrine" aria-label="Permalink to &quot;Current Doctrine&quot;">​</a></h2><p>QiAccess Start currently operates as a Markdown/YAML doctrine vault rooted in <code>docs/</code>, with qiserver as the active runtime host and QiNexus as the storage backbone.</p><p>Relational schema material below is retained as legacy/reference-only or future/conditional architecture guidance. Supabase is not active unless it has a specific job. <code>pgvector</code> is not active unless a future retrieval pipeline explicitly needs it.</p><h2 id="schema-philosophy" tabindex="-1">Schema Philosophy <a class="header-anchor" href="#schema-philosophy" aria-label="Permalink to &quot;Schema Philosophy&quot;">​</a></h2><p>If a future relational layer is activated for a specific job, the schema should reflect the fact that the system is:</p><ul><li><strong>modular</strong> — each domain lives in its own Postgres schema</li><li><strong>identity-driven</strong> — every record has a canonical ID that survives transformation</li><li><strong>archive-aware</strong> — ingested files register in <code>qiarchive</code> before downstream processing</li><li><strong>retrieval-oriented</strong> — embeddings and vector search are future/conditional rather than current doctrine</li><li><strong>graph-projectable</strong> — <code>qigraph</code> is always derived from, never the source of, canonical records</li></ul><p>The active doctrine in this repo is not a live relational platform. If a relational layer is reactivated, it should remain relational at the core, with vector and graph layers derived from stable canonical records.</p><h2 id="legacy-conditional-namespace-map-reference-only" tabindex="-1">Legacy / Conditional Namespace Map (Reference Only) <a class="header-anchor" href="#legacy-conditional-namespace-map-reference-only" aria-label="Permalink to &quot;Legacy / Conditional Namespace Map (Reference Only)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Schema</th><th>Band</th><th>Role</th></tr></thead><tbody><tr><td><code>qione</code></td><td>Platform</td><td>Modular registry and app config reference only; tenants/RBAC remain future/conditional</td></tr><tr><td><code>qiarchive</code></td><td>Core</td><td>File registration, archive spine</td></tr><tr><td><code>qigraph</code></td><td>Core</td><td>Derived knowledge graph</td></tr><tr><td><code>qially</code></td><td>Core</td><td>AI sessions, messages, memory</td></tr><tr><td><code>qisys</code></td><td>Core</td><td>Jobs, events, worker status</td></tr><tr><td><code>qievidence</code></td><td>Domain</td><td>Local-first evidence intelligence</td></tr><tr><td><code>qicase</code></td><td>Domain</td><td>Legal case management</td></tr><tr><td><code>qichronicle</code></td><td>Domain</td><td>Events and calendar</td></tr><tr><td><code>qicms</code></td><td>Domain</td><td>Content and posts</td></tr><tr><td><code>qihome</code></td><td>Domain</td><td>Household and finances</td></tr><tr><td><code>qiknowledge</code></td><td>Domain</td><td>Notes and writing</td></tr><tr><td><code>qitax</code></td><td>Domain</td><td>Tax returns</td></tr><tr><td><code>qivault</code></td><td>Domain</td><td>Secure documents</td></tr><tr><td><code>qicare</code></td><td>Domain</td><td>Respiratory and health care management</td></tr><tr><td><code>public</code></td><td>Platform</td><td>Legacy stubs only - no new tables</td></tr></tbody></table><h2 id="reconciliation-schema-vs-data-vs-object" tabindex="-1">Reconciliation: Schema vs Data vs Object <a class="header-anchor" href="#reconciliation-schema-vs-data-vs-object" aria-label="Permalink to &quot;Reconciliation: Schema vs Data vs Object&quot;">​</a></h2><p>These three things are distinct. Conflating them creates drift.</p><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong>Schema</strong></td><td>The structural shape defined in Postgres (columns, types, constraints)</td></tr><tr><td><strong>Data</strong></td><td>The raw or unstructured payload stored at ingest</td></tr><tr><td><strong>Object</strong></td><td>The domain-level entity mapped from schema + enriched data</td></tr></tbody></table><p><strong>Rule</strong>: Never let a downstream object layer redefine what the schema says is true.</p><h2 id="core-early-tables-spine-required" tabindex="-1">Core Early Tables (Spine-Required) <a class="header-anchor" href="#core-early-tables-spine-required" aria-label="Permalink to &quot;Core Early Tables (Spine-Required)&quot;">​</a></h2><p>As defined in the QiOS Master Blueprint genesis:</p><ul><li><code>qiarchive.archive_files</code> — canonical file registration ✅</li><li><code>qiarchive.archive_chunks</code> — chunked text records ✅</li><li><code>qiarchive.ingest_jobs</code> — pipeline state tracking ✅</li><li><code>qiarchive.file_history</code> — lineage and rename tracking ✅</li><li><code>qione.app_module_registry</code> — modular capability tracking ✅</li><li><code>qione.tenants</code> — tenant identity (Platform-Future) ✅</li><li><code>qigraph.master_index</code> — cross-domain object index ✅</li><li><code>qisys.devices</code> — enrolled machine identities</li><li><code>qisys.device_agents</code> — local agent service states</li><li><code>qisys.device_heartbeats</code> — node health checks</li><li><code>qisys.device_jobs</code> — dispatched node tasks</li><li><code>qisys.device_events</code> — fleet audit trail</li><li><code>qisys.device_capabilities</code> — node role and hardware spec</li><li><code>qisys.device_watch_assignments</code> — folder and drop zone policies</li></ul><h2 id="email-intake-schema-contract" tabindex="-1">Email Intake Schema Contract <a class="header-anchor" href="#email-intake-schema-contract" aria-label="Permalink to &quot;Email Intake Schema Contract&quot;">​</a></h2><p>Email is modeled as an integration feeding the master archival spine, avoiding a separate schema. It is bounded by these core table definitions:</p><ul><li><code>qione.email_accounts</code> — user-owned integration integration ownership and IMAP/Gmail/connector configuration.</li><li><code>qiarchive.archive_messages</code> — canonical registration for individual email payloads.</li><li><code>qiarchive.archive_message_threads</code> — canonical grouping of related messages.</li><li><code>qiarchive.archive_message_participants</code> — sender/recipient edge metadata.</li><li><code>qiarchive.archive_message_attachments</code> — canonical attachment metadata. Email attachments processed as robust files must receive an <code>archive_id</code>.</li><li><code>qisys.email_sync_cursors</code> — connector synchronization state, jobs, and webhook checkpoints.</li><li><code>qially</code> tracking — provenance-aware memory and embeddings for email-derived knowledge chunks must link back to their canonical archive IDs.</li></ul><hr><h2 id="canonical-record-invariants" tabindex="-1">Canonical Record Invariants <a class="header-anchor" href="#canonical-record-invariants" aria-label="Permalink to &quot;Canonical Record Invariants&quot;">​</a></h2><p>QiOS supports modular, domain-specific schemas. Canonical records should conform to a shared minimum invariant set unless the table&#39;s purpose or an approved ADR justifies an exception. Every record passing through the intake pipeline must also capture fleet provenance fields (<code>owner_user_id</code>, <code>source_device_id</code>, <code>source_agent_id</code>, <code>source_path</code>, <code>ingest_mode</code>) so ingestion is fully traceable and isolated.</p><h3 id="common-field-invariants" tabindex="-1">Common Field Invariants <a class="header-anchor" href="#common-field-invariants" aria-label="Permalink to &quot;Common Field Invariants&quot;">​</a></h3><p>Canonical domain records should implement the following common fields unless the table serves a narrowly scoped structural purpose or an approved ADR defines an exception:</p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Role</th></tr></thead><tbody><tr><td><code>id</code></td><td><code>uuid</code></td><td>Canonical unique identifier for the record.</td></tr><tr><td><code>owner_user_id</code></td><td><code>uuid</code></td><td>Reference to the owning user identity in a future relational/auth-backed layer.</td></tr><tr><td><code>status</code></td><td><code>text</code></td><td>Lifecycle state for governance, routing, or operational control.</td></tr><tr><td><code>visibility</code></td><td><code>text</code></td><td>Visibility or access classification for governed read exposure.</td></tr><tr><td><code>metadata</code></td><td><code>jsonb</code></td><td>System-governed provenance, lineage, and auxiliary indexing metadata.</td></tr><tr><td><code>source_device_id</code></td><td><code>uuid</code></td><td>Identifying the enrolled ingestion node.</td></tr><tr><td><code>source_agent_id</code></td><td><code>uuid</code></td><td>Identifying the agent runner instance.</td></tr><tr><td><code>source_path</code></td><td><code>text</code></td><td>Original ingress pathway or drop zone.</td></tr><tr><td><code>ingest_mode</code></td><td><code>text</code></td><td>e.g. <code>drop_zone</code>, <code>watcher</code>, <code>manual_upload</code>, <code>sync_worker</code></td></tr></tbody></table><p>Domain-specific fields should be modeled as typed relational columns by default. An <code>attributes</code> or equivalent extensibility field may be used only where flexibility is justified and does not replace stable schema design.</p><h2 id="schema-governance-invariants" tabindex="-1">Schema Governance Invariants <a class="header-anchor" href="#schema-governance-invariants" aria-label="Permalink to &quot;Schema Governance Invariants&quot;">​</a></h2><ul><li><strong>Migration-as-Truth</strong>: If a relational schema is activated for a specific job, database migrations are the canonical schema authority for that layer. ORMs and client models may reflect the schema, but they do not define it.</li><li><strong>Relational Core</strong>: If used, the relational layer remains downstream-safe. Vector, graph, and AI-derived structures must remain downstream of stable canonical records and preserve traceable linkage back to them.</li><li><strong>Domain Isolation</strong>: Domain ownership must remain local to the owning schema. Cross-domain dependencies must not create hidden coupling or competing sources of truth. Inter-domain resolution should occur through governed registry patterns, approved interfaces, or the application layer unless an ADR explicitly permits tighter database-level integration.</li><li><strong>Audit Requirements</strong>: Canonical tables should maintain <code>created_at</code> and <code>updated_at</code> timestamps unless the table is append-only, purely structural, or explicitly exempted by doctrine or ADR.</li></ul><h2 id="namespace-allocation-governance" tabindex="-1">Namespace Allocation Governance <a class="header-anchor" href="#namespace-allocation-governance" aria-label="Permalink to &quot;Namespace Allocation Governance&quot;">​</a></h2><p>Namespace routing is governed separately from relational identity.</p><p>Canonical records such as contacts, users, clients, cases, and matters must use relational identifiers as their source of truth. Namespace codes may be attached only when a governed routed container is required.</p><h3 id="minimum-registry-requirements" tabindex="-1">Minimum Registry Requirements <a class="header-anchor" href="#minimum-registry-requirements" aria-label="Permalink to &quot;Minimum Registry Requirements&quot;">​</a></h3><p>A namespace allocation system must record:</p><ul><li>allocation identifier</li><li>namespace code</li><li>owner type</li><li>owner identifier</li><li>band class</li><li>status</li><li>created_at</li><li>updated_at</li></ul><h3 id="compliance-rules" tabindex="-1">Compliance Rules <a class="header-anchor" href="#compliance-rules" aria-label="Permalink to &quot;Compliance Rules&quot;">​</a></h3><p>Namespace allocations must:</p><ul><li>map to an approved band</li><li>remain unique within the allocation registry</li><li>target an approved owner type</li><li>respect reserved ranges</li><li>avoid implicit invention of new band classes or code patterns</li></ul><h3 id="forbidden-pattern" tabindex="-1">Forbidden Pattern <a class="header-anchor" href="#forbidden-pattern" aria-label="Permalink to &quot;Forbidden Pattern&quot;">​</a></h3><p>Do not allocate namespace codes to every contact, login, or row merely for symmetry. Routing allocation is operational and architectural, not ornamental.</p>',40)])])}const p=t(r,[["render",d]]);export{u as __pageData,p as default};
